def flatten(lst: list) -> list:
    """
    Flattens an arbitrarily nested list into a single-level list.
    """
    flat_list = []

    for item in lst:
        # Check if the item is a list (or tuple) to handle nested structures
        if isinstance(item, list):
            # Recursively call flatten and extend the result list
            flat_list.extend(flatten(item))
        else:
            # If it's a base element, just append it
            flat_list.append(item)

def binary_search(arr, target):
    left, right = 0, len(arr) - 1
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1
    return -1

